import type { MCQQuestion } from "@/types";

// GMAT Focus Edition — Verbal Reasoning
// 230 questions across 10 tests (23 per test)
// RC questions carry full passage text in the `passage` field so they're self-contained.

// ── Shared passages (reused within a test's RC set) ──────────────────────
const P_BEHAVIORAL_ECON = "Behavioral economics challenges traditional models that assume rational actors. Kahneman and Tversky showed humans exhibit systematic biases: loss aversion (valuing losses ~2× more than equivalent gains) and anchoring (over-relying on the first number encountered). These insights inform 'nudge' policy — guiding choices without restricting them.";

const P_GIG_ECONOMY = "The gig economy has expanded rapidly, offering workers flexibility but reducing job security and benefits. Proponents argue it democratizes entrepreneurship. Critics contend it externalizes business risk onto workers who lack negotiating power.";

const P_AI_EMERGENCE = "Artificial intelligence systems trained on large datasets can exhibit emergent capabilities — behaviors not explicitly programmed and not present in smaller models. This unpredictability complicates safety testing: engineers cannot enumerate all inputs that might trigger harmful outputs. Proponents argue emergence enables unprecedented problem-solving; critics counter that opaque, emergent systems are inherently ungovernable.";

const P_MICROPLASTICS = "Microplastics — particles smaller than 5 mm — have been detected in oceans, soil, drinking water, and human tissue. While their prevalence is undisputed, long-term health impacts remain poorly understood. Studies on marine animals show cellular damage, but extrapolating to humans is scientifically contested. Regulatory bodies have called for precautionary limits, while industry groups argue current evidence is insufficient to justify restrictive policy.";

const P_REMOTE_WORK = "Studies of remote work during the pandemic produced contradictory findings. Some researchers reported productivity gains of 10–15%, attributing them to reduced commute time and fewer office interruptions. Others found declines in collaboration quality and innovation, arguing that serendipitous in-person interactions are irreplaceable. A third cluster of studies found no significant productivity change, suggesting individual and organizational factors mediate outcomes.";

const P_URBAN_HEAT = "Urban heat islands arise when cities absorb and re-emit more heat than surrounding rural areas, primarily due to impervious surfaces, low vegetation, and waste heat from transportation. Temperatures in urban cores can exceed rural areas by 2–5°C, increasing energy demand, worsening air quality, and raising heat-related mortality. Green roofs, reflective pavements, and urban forests have been proposed as mitigation strategies, though each carries distinct cost and feasibility trade-offs.";

const P_ANTIBIOTIC_RESIST = "Antibiotic resistance is accelerating globally, driven by overuse in human medicine and agriculture. When bacteria survive antibiotic exposure, resistant strains propagate; plasmids can transfer resistance genes between species rapidly. The WHO classifies antimicrobial resistance as one of the top global public health threats. Development of new antibiotics has slowed dramatically since the 1980s, as pharmaceutical companies find the business model unattractive relative to drugs taken chronically.";

const P_CARBON_CAPTURE = "Carbon capture and storage (CCS) involves removing CO₂ from emission sources or the atmosphere and sequestering it underground. Proponents see CCS as essential to meeting net-zero targets alongside renewable energy. Critics argue CCS is costly, energy-intensive, and provides cover for continued fossil fuel use. A 2023 meta-analysis found that existing CCS projects capture roughly 40 million tonnes annually — less than 0.1% of global emissions.";

const P_SOCIAL_MEDIA_TEEN = "A longitudinal study tracked 5,000 adolescents over four years, measuring social media use and self-reported well-being. Heavier users reported lower life satisfaction, though the effect size was small (r = 0.12). Critics of the study noted that reverse causation — unhappy teens seeking social media — was not ruled out, and that correlational findings should not drive policy. Proponents argued the precautionary principle justified action even under uncertainty.";

const P_SUPPLY_CHAIN = "Global supply chains became more fragile when COVID-19 exposed the vulnerability of just-in-time (JIT) manufacturing. JIT, which minimizes inventory to reduce holding costs, depends on reliable, rapid delivery from geographically dispersed suppliers. Disruptions in one node can cascade globally. Post-pandemic, firms are debating reshoring (moving production domestically), nearshoring (moving to nearby countries), and buffer stock strategies — each with different cost and resilience trade-offs.";

// ── Additional passages for banks T11–T15 ─────────────────────────────────
const P_GENE_EDITING = "CRISPR-Cas9 technology enables precise editing of DNA sequences by guiding an enzyme to a target genomic location. Applications range from correcting inherited disorders to developing disease-resistant crops. Off-target edits — cuts at unintended genomic sites — remain a safety concern. Proponents argue CRISPR's precision far exceeds prior gene-editing methods; critics contend that unintended edits in germline cells could propagate heritable changes across generations.";
const P_AUTOMATION_JOBS = "Automation's effect on employment is debated. Economists who argue automation destroys jobs cite historical displacement of manufacturing workers. Economists who argue automation creates jobs note that new industries emerged after each wave of mechanization. A third view holds that automation redistributes work — reducing hours in some occupations while expanding others — with aggregate employment stable but income distribution shifting toward capital owners.";
const P_DIGITAL_PRIVACY = "Data privacy regulations such as GDPR impose consent requirements on firms collecting personal data. Proponents argue these rules restore individual control and reduce surveillance capitalism. Critics contend that compliance costs disadvantage smaller firms, fragment the global internet, and impose consent-fatigue on users who click through notices without reading them.";
const P_LONGEVITY_RESEARCH = "Research into biological aging suggests that cellular senescence — the accumulation of non-dividing 'zombie' cells — drives chronic inflammation and age-related disease. Senolytic drugs that selectively eliminate senescent cells have extended healthy lifespan in animal models. Human trials are early-stage; preliminary data show reduced inflammation markers. Gerontologists caution that animal-to-human translation in aging research has historically had a poor track record.";
const P_SPACE_COMMERCIAL = "Commercial launch providers have reduced the cost of reaching low Earth orbit from roughly $54,000 per kilogram in the 1980s to under $3,000 today. This drop has enabled satellite constellations for broadband and Earth observation. Concerns include orbital congestion and the Kessler syndrome — a cascade in which one debris collision triggers further collisions, potentially rendering orbit unusable — as well as gaps in international space law.";
const P_CENTRAL_BANKS = "Central banks use interest rate policy and balance-sheet operations to manage inflation and employment. Post-2008 quantitative easing dramatically expanded central bank balance sheets. Critics argue it inflated asset prices and widened wealth inequality. Defenders argue it prevented deflation and supported employment. The post-COVID inflation surge reignited debate about whether prolonged low rates embedded inflationary expectations.";
const P_OPEN_SOURCE = "Open-source software is developed collaboratively with source code publicly available for inspection, modification, and redistribution. Proponents argue it accelerates innovation and reduces vendor lock-in. Critics note that maintenance is often sustained by a small group of underfunded volunteers, creating systemic fragility — illustrated when a single widely-used package became a critical dependency with no redundancy in global software infrastructure.";
const P_CLIMATE_ADAPTATION = "Adaptation to climate change involves adjusting systems to reduce vulnerability to projected impacts. Unlike mitigation — which cuts emissions — adaptation accepts some degree of climate change as inevitable. Managed retreat, relocating communities from flood-prone coastlines, is the most controversial adaptation strategy because it requires governments to compel or incentivize relocation, raising issues of property rights, cultural identity, and distributional equity.";
const P_NUTRITION_SCIENCE = "Nutritional epidemiology relies largely on self-reported dietary recall data, subject to memory error and social desirability bias. Critics argue these weaknesses render most dietary recommendations scientifically unreliable. Defenders note that long-duration randomized controlled trials of diet are impractical, and that observational evidence — while imperfect — can identify broad dietary patterns associated with health outcomes.";
const P_VOTING_SYSTEMS = "Electoral systems shape political representation. Plurality voting — where the candidate with the most votes wins — tends to produce two-party systems (Duverger's Law). Proportional representation produces multi-party legislatures that more accurately mirror voter preferences but often require coalition governments. Ranked-choice voting allows voters to rank candidates, potentially reducing spoiler effects and incentivizing less negative campaigning.";

